Substantial trading volume refers to instruments with more than 5,000,000 traded shares; the most active instruments are those with the highest trading volumes.;
Financial instruments are traded in markets; each instrument is listed with a unique ticker symbol.;
The SQL query aggregates trading volumes by each instrument to determine their activity level.;

sql:
SELECT AVG(volume) AS average_volume
FROM market_data
WHERE instrument_id = 1 AND trade_date BETWEEN '2022-01-01' AND '2022-03-01';

SELECT AVG(open_price) AS avg_open_price
FROM market_data 
WHERE instrument_id = (SELECT instrument_id FROM instruments WHERE ticker = 'BCC');

SELECT portfolio_name
FROM portfolios
WHERE user_id = 1;

SELECT COUNT(instrument_id) AS number_of_instruments
FROM indicator_instruments
WHERE indicator_id = 1 AND impact_factor > 0.5;

SELECT SUM(p.quantity * m.close_price) AS Total_Open_Position_Value
FROM portfolio_instruments p
JOIN market_data m ON p.instrument_id = m.instrument_id;

SELECT source_name, last_synced
FROM external_data_sources
ORDER BY last_synced DESC;
